// HasUsuariosEmpresa applies the HasEdge predicate on the "usuarios_empresa" edge.
func HasUsuariosEmpresa() predicate.Empresa {
	return predicate.Empresa(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, UsuariosEmpresaTable, UsuariosEmpresaColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUsuariosEmpresaWith applies the HasEdge predicate on the "usuarios_empresa" edge with a given conditions (other predicates).
func HasUsuariosEmpresaWith(preds ...predicate.EmpresaUsuario) predicate.Empresa {
	return predicate.Empresa(func(s *sql.Selector) {
		step := newUsuariosEmpresaStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

